class ASTNode:
    def __init__(self, node_type, **kwargs):
        self.type = node_type
        if node_type == "number":
            self.value = kwargs.get("value")
        elif node_type == "binop":
            self.op = kwargs.get("op")
            self.left = kwargs.get("left")
            self.right = kwargs.get("right")
        elif node_type == "unary":
            self.op = kwargs.get("op")
            self.operand = kwargs.get("operand")

    def __repr__(self) -> str:
        if self.type == "number":
            return f"Number({self.value})"
        elif self.type == "binop":
            return f"BinOp({self.op}, {self.left}, {self.right})"
        elif self.type == "unary":
            return f"UnaryOp({self.op}, {self.operand})"
        return f"ASTNode({self.type})"


def parse(expression: str) -> ASTNode:
    if not expression.strip():
        raise ValueError("Empty expression")

    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("No tokens found in expression")

    return parse_expression(tokens)


def tokenize(expression: str):
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c.isdigit() or c == ".":
            num_str = []
            while i < n and (expression[i].isdigit() or expression[i] == "."):
                num_str.append(expression[i])
                i += 1
            if len(num_str) > 1 and num_str.count(".") > 1:
                raise ValueError("Invalid number format")
            tokens.append(("number", float("".join(num_str))))
        elif c in "+-*/()":
            tokens.append(("operator", c))
            i += 1
        else:
            raise ValueError(f"Invalid token: {c}")

    return tokens


def parse_expression(tokens, precedence={"+": 1, "-": 1, "*": 2, "/": 2}):
    def parse_binary_op(min_precedence):
        left = parse_primary()

        while tokens and tokens[0][0] == "operator" and tokens[0][1] in precedence:
            op_token = tokens[0][1]
            op_precedence = precedence[op_token]

            if op_precedence < min_precedence:
                break

            tokens.pop(0)
            right = parse_binary_op(op_precedence + 1)
            left = ASTNode("binop", op=op_token, left=left, right=right)

        return left

    def parse_primary():
        if not tokens:
            raise ValueError("Unexpected end of expression")

        token_type, token_value = tokens[0]

        if token_type == "number":
            tokens.pop(0)
            return ASTNode("number", value=token_value)
        elif token_value == "(":
            tokens.pop(0)
            expr = parse_binary_op(0)
            if not tokens or tokens[0][1] != ")":
                raise ValueError("Unmatched parentheses")
            tokens.pop(0)
            return expr
        elif token_value == "-":
            tokens.pop(0)
            operand = parse_primary()
            return ASTNode("unary", op="-", operand=operand)
        elif token_value == "+":
            tokens.pop(0)
            operand = parse_primary()
            return operand
        else:
            raise ValueError(f"Unexpected token: {token_value}")

    return parse_binary_op(0)


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
        elif node.op == "+":
            return operand_val

    raise ValueError(f"Unknown node type: {node.type}")
